// Извлекаем base64 из входящего запроса
// Сайт шлёт multipart/form-data с полями: photo (файл) и/или base64
const body = $input.first().json.body || {};
const binaryData = $input.first().binary || {};

let base64Image = '';
let mimeType = 'image/jpeg';

// Пробуем взять файл из binary
if (binaryData.photo && binaryData.photo.data) {
  base64Image = binaryData.photo.data;
  mimeType = binaryData.photo.mimeType || 'image/jpeg';
} else if (body.base64) {
  // Или берём base64 из поля
  base64Image = body.base64.replace(/^data:image\/[a-z]+;base64,/, '');
}

if (!base64Image) {
  throw new Error('Нет изображения в запросе');
}

return [{
  json: {
    base64: base64Image,
    mimeType: mimeType,
    source: body.source || 'website',
    timestamp: body.timestamp || new Date().toISOString()
  }
}];

// Парсим JSON-ответ от llava-phi3
const raw = $input.first().json.response || '';

let parsed = {};
try {
  // GPT/Ollama иногда оборачивает JSON в ```json ... ```
  const cleaned = raw
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();

  // Ищем JSON-объект в ответе
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) {
    parsed = JSON.parse(match[0]);
  } else {
    throw new Error('JSON not found');
  }
} catch(e) {
  // Если парсинг не удался — делаем базовый результат
  parsed = {
    plant_name: 'Растение',
    disease: 'Не удалось определить',
    disease_category: 'unknown',
    severity: 'warn',
    confidence: 50,
    diagnosis: 'Нейросеть не смогла однозначно определить проблему. Попробуйте сделать более чёткое фото поражённого места.',
    recommendations: '1. Сделайте фото крупным планом\n2. Убедитесь в хорошем освещении\n3. Сфотографируйте обе стороны листа',
    urgency: 'Повторите с более чётким фото',
    show_on_site: false
  };
}

const prevData = $('Извлечь изображение').first().json;

return [{
  json: {
    ...parsed,
    source: prevData.source || 'website',
    timestamp: prevData.timestamp || new Date().toISOString(),
    raw_response: raw
  }
}];

// Формируем красивый ответ для сайта
const diagnosis = $('Парсить ответ Ollama').first().json;
const dbRow = $input.first().json;

const sevEmoji = { ok: '✅', warn: '⚠️', danger: '🚨' }[diagnosis.severity] || '⚠️';

return [{
  json: {
    id: dbRow.id || Date.now(),
    plant_name: diagnosis.plant_name,
    disease: diagnosis.disease,
    disease_category: diagnosis.disease_category,
    severity: diagnosis.severity,
    confidence: diagnosis.confidence,
    diagnosis: diagnosis.diagnosis,
    recommendations: diagnosis.recommendations,
    urgency: diagnosis.urgency,
    statusLabel: diagnosis.disease,
    status: diagnosis.severity,
    date: new Date().toLocaleString('ru-RU', { day:'2-digit', month:'2-digit', year:'numeric', hour:'2-digit', minute:'2-digit' }),
    icon: sevEmoji,
    show_on_site: diagnosis.show_on_site,
    _source: 'analysis-complete'
  }
}];

// Форматируем список для карусели сайта
const rows = $input.all();

const result = rows.map(row => {
  const d = row.json;
  const dateStr = new Date(d.created_at || Date.now())
    .toLocaleString('ru-RU', { day:'2-digit', month:'2-digit', year:'numeric', hour:'2-digit', minute:'2-digit' });

  return {
    id: d.id,
    name: d.name || 'Растение',
    plant_name: d.name || 'Растение',
    statusLabel: d.statusLabel || d.disease || 'Анализ',
    disease: d.statusLabel || 'Анализ',
    status: d.status || d.severity || 'warn',
    severity: d.status || 'warn',
    confidence: d.confidence || 0,
    diagnosis: d.diagnosis || '',
    diagnosis_text: d.diagnosis || '',
    recommendation: d.recommendation || '',
    recommendations: d.recommendation || '',
    urgency: d.urgency || '',
    date: dateStr,
    img: `/plant-doctor/placeholder.svg`,
    img_url: `/plant-doctor/placeholder.svg`,
    source: d.source || 'website'
  };
});

return [{ json: result }];
